1	import { describe, it, expect } from "vitest";
2	import request from "supertest";
3	import { app } from "../src/app.js";
4	
5	describe("GET /products", () => {
6	  it("should return all products with summary", async () => {
7	    const res = await request(app).get("/products");
8	    expect(res.status).toBe(200);
9	    expect(res.body.products.length).toBe(5);
10	    expect(res.body.summary).toHaveProperty("count");
11	    expect(res.body.summary).toHaveProperty("totalInventoryValue");
12	    expect(res.body.summary).toHaveProperty("averagePrice");
13	  });
14	
15	  it("should filter by category", async () => {
16	    const res = await request(app).get("/products?category=furniture");
17	    expect(res.status).toBe(200);
18	    expect(res.body.products.length).toBe(2);
19	    expect(res.body.products.every((p: any) => p.category === "furniture")).toBe(
20	      true
21	    );
22	  });
